  1→import { useState, useCallback, useRef, useEffect } from 'react';
  2→import { useQueryClient, useQuery } from '@tanstack/react-query';
  3→import { useProjects } from '@/hooks/useProjects';
  4→import { useFacetAggregation, useReflectSnapshot, useReflectWeeks } from '@/hooks/useReflect';
  5→import { reflectGenerateStream, fetchOutdatedFacetCount } from '@/lib/api';
  6→import { WeekSelector } from '@/components/patterns/WeekSelector';
  7→import { WeekAtAGlanceStrip } from '@/components/patterns/WeekAtAGlanceStrip';
  8→import { CollapsibleCategoryList } from '@/components/patterns/CollapsibleCategoryList';
  9→import { WorkingStyleHighlights } from '@/components/patterns/WorkingStyleHighlights';
 10→import { getCurrentIsoWeek, formatRelativeDate } from '@/lib/date-utils';
 11→import { parseSSEStream } from '@/lib/sse';
 12→import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
 13→import { Button } from '@/components/ui/button';
 14→import { Badge } from '@/components/ui/badge';
 15→import { Skeleton } from '@/components/ui/skeleton';
 16→import { Tabs, TabsList, TabsTrigger, TabsContent } from '@/components/ui/tabs';
 17→import { Alert, AlertDescription } from '@/components/ui/alert';
 18→import { ErrorCard } from '@/components/ErrorCard';
 19→import { frictionBarColor, getDominantDriver } from '@/lib/constants/patterns';
 20→import {
 21→  AlertTriangle, Sparkles, Shield, Brain, Copy, Check, Loader2,
 22→} from 'lucide-react';
 23→
 24→export default function PatternsPage() {
 25→  const [currentWeek, setCurrentWeek] = useState<string>(() => getCurrentIsoWeek());
 26→  const [selectedProject, setSelectedProject] = useState<string | undefined>(undefined);
 27→  const [generating, setGenerating] = useState(false);
 28→  const [generationProgress, setGenerationProgress] = useState('');
 29→  const [reflectResults, setReflectResults] = useState<Record<string, unknown> | null>(null);
 30→  const [copiedKey, setCopiedKey] = useState<string | null>(null);
 31→  const abortRef = useRef<AbortController | null>(null);
 32→  const queryClient = useQueryClient();
 33→
 34→  const { data: projects = [] } = useProjects();
 35→
 36→  const { data: weeksData } = useReflectWeeks({ project: selectedProject });
 37→  const weeks = weeksData?.weeks ?? [];
 38→
 39→  const { data: snapshotData } = useReflectSnapshot({
 40→    period: currentWeek,
 41→    project: selectedProject,
 42→  });
 43→
 44→  const { data: aggregation, isLoading, isError, refetch } = useFacetAggregation({
 45→    period: currentWeek,
 46→    project: selectedProject,
 47→  });
 48→
 49→  const { data: outdatedData } = useQuery({
 50→    queryKey: ['facets', 'outdated', selectedProject, currentWeek],
 51→    queryFn: () => fetchOutdatedFacetCount({ project: selectedProject, period: currentWeek }),
 52→    staleTime: 5 * 60 * 1000,
 53→  });
 54→
 55→  const outdatedCount = outdatedData?.count ?? 0;
 56→
 57→  // Abort in-flight generation on unmount
 58→  useEffect(() => {
 59→    return () => {
 60→      abortRef.current?.abort();
 61→    };
 62→  }, []);
 63→
 64→  // On initial load, jump to the most recent week that has a snapshot.
 65→  // This avoids showing the current week with no data when reflections exist for recent weeks.
 66→  // Only runs once (when weeks first loads) — tracked by whether currentWeek is still the computed default.
 67→  const initialWeekRef = useRef<string>(getCurrentIsoWeek());
 68→  useEffect(() => {
 69→    if (!weeksData?.weeks.length) return;
 70→    if (currentWeek !== initialWeekRef.current) return; // user already navigated
 71→    const mostRecentWithSnapshot = weeksData.weeks.find(w => w.hasSnapshot);
 72→    if (mostRecentWithSnapshot && mostRecentWithSnapshot.week !== currentWeek) {
 73→      handleWeekChange(mostRecentWithSnapshot.week);
 74→    }
 75→  // eslint-disable-next-line react-hooks/exhaustive-deps
 76→  // Intentional: handleWeekChange is stable (useCallback with no deps) and initialWeekRef
 77→  // is a ref — neither should trigger re-runs. Re-running on every render would break the
 78→  // "jump to most recent snapshot only on initial load" logic.
 79→  }, [weeksData]);
 80→
 81→  // Auto-load cached snapshot when it arrives and no local results exist yet
 82→  useEffect(() => {
 83→    if (snapshotData?.snapshot?.results && !reflectResults && !generating) {
 84→      setReflectResults(snapshotData.snapshot.results);
 85→    }
 86→  }, [snapshotData, reflectResults, generating]);
 87→
 88→  const handleWeekChange = useCallback((week: string) => {
 89→    setCurrentWeek(week);
 90→    setReflectResults(null);
 91→  }, []);
 92→
 93→  const handleProjectChange = useCallback((projectId: string | undefined) => {
 94→    setSelectedProject(projectId);
 95→    setReflectResults(null);
 96→    // Reset to current week so auto-navigation re-fires for the new project context.
 97→    // The initialWeekRef guard in the auto-navigate effect uses getCurrentIsoWeek(),
 98→    // so resetting currentWeek to that value re-enables the "jump to most recent snapshot" logic.
 99→    setCurrentWeek(getCurrentIsoWeek());
100→    initialWeekRef.current = getCurrentIsoWeek();
101→  }, []);
102→
103→  const handleGenerate = useCallback(async () => {
104→    abortRef.current?.abort();
105→    const controller = new AbortController();
106→    abortRef.current = controller;
107→
108→    setGenerating(true);
109→    setGenerationProgress('Starting...');
110→    setReflectResults(null);
111→
112→    try {
113→      const response = await reflectGenerateStream(
114→        { period: currentWeek, project: selectedProject },
115→        controller.signal
116→      );
117→
118→      if (!response.body) throw new Error('No response body');
119→
120→      for await (const event of parseSSEStream(response.body)) {
121→        if (event.event === 'progress') {
122→          try {
123→            const data = JSON.parse(event.data) as { message?: string };
124→            setGenerationProgress(data.message || 'Processing...');
125→          } catch { /* skip malformed event */ }
126→        } else if (event.event === 'complete') {
127→          try {
128→            const data = JSON.parse(event.data) as { results?: Record<string, unknown> };
129→            setReflectResults(data.results ?? null);
130→            queryClient.invalidateQueries({ queryKey: ['reflect', 'snapshot'] });
131→          } catch { /* skip malformed event */ }
132→        } else if (event.event === 'error') {
133→          try {
134→            const data = JSON.parse(event.data) as { error?: string };
135→            setGenerationProgress(`Error: ${data.error ?? 'Unknown error'}`);
136→          } catch { /* skip malformed event */ }
137→        }
138→      }
139→    } catch (err) {
140→      if (err instanceof Error && err.name === 'AbortError') return;
141→      setGenerationProgress(err instanceof Error ? err.message : 'Generation failed');
142→    } finally {
143→      setGenerating(false);
144→    }
145→  }, [currentWeek, selectedProject, queryClient]);
146→
147→  const handleCopy = useCallback((text: string, key: string) => {
148→    navigator.clipboard.writeText(text);
149→    setCopiedKey(key);
150→    setTimeout(() => setCopiedKey(null), 2000);
151→  }, []);
152→
153→  if (isLoading) {
154→    return (
155→      <div className="space-y-6 p-4 lg:p-6">
156→        <Skeleton className="h-8 w-48" />
157→        <div className="grid gap-4 md:grid-cols-3">
158→          <Skeleton className="h-32" />
159→          <Skeleton className="h-32" />
160→          <Skeleton className="h-32" />
161→        </div>
162→        <Skeleton className="h-64" />
163→      </div>
164→    );
165→  }
166→
167→  if (isError) {
168→    return (
169→      <div className="p-4 lg:p-6">
170→        <ErrorCard message="Failed to load patterns data" onRetry={refetch} />
171→      </div>
172→    );
173→  }
174→
175→  // --- Derived data ---
176→
177→  const frictionItems = (aggregation?.frictionCategories || []).slice(0, 10).map(fc => ({
178→    category: fc.category,
179→    count: fc.count,
180→    severity: Math.round(fc.avg_severity * 10) / 10,
181→    color: frictionBarColor(fc.avg_severity),
182→    descriptions: fc.examples,
183→  }));
184→
185→  const patternItems = (aggregation?.effectivePatterns || []).slice(0, 8).map(ep => ({
186→    category: ep.label,
187→    count: ep.frequency,
188→    descriptions: ep.descriptions,
189→    driver: getDominantDriver(ep.drivers),
190→  }));
191→
192→  const hasEnoughFacets = (aggregation?.totalSessions ?? 0) >= 8;
193→  const coverageRatio = aggregation && aggregation.totalAllSessions > 0
194→    ? aggregation.totalSessions / aggregation.totalAllSessions
195→    : 0;
196→
197→  const rulesSkillsResult = reflectResults?.['rules-skills'] as Record<string, unknown> | undefined;
198→  const workingStyleResult = reflectResults?.['working-style'] as Record<string, unknown> | undefined;
199→
200→  const tagline = workingStyleResult?.tagline as string | undefined;
201→  const narrative = workingStyleResult?.narrative as string | undefined;
202→
203→  // Derive working style highlights from aggregation data
204→  // DB stores outcome_satisfaction as 'high' | 'medium' | 'low' | 'abandoned' — NOT 'success'
205→  const successCount = aggregation?.outcomeDistribution?.['high'] ?? 0;
206→
207→  const topCharacterEntry = aggregation?.characterDistribution
208→    ? Object.entries(aggregation.characterDistribution).sort((a, b) => b[1] - a[1])[0]
209→    : null;
210→  const totalCharacters = aggregation?.characterDistribution
211→    ? Object.values(aggregation.characterDistribution).reduce((s, v) => s + v, 0)
212→    : 0;
213→  const topCharacter = topCharacterEntry && totalCharacters > 0
214→    ? { name: topCharacterEntry[0], percentage: Math.round((topCharacterEntry[1] / totalCharacters) * 100) }
215→    : undefined;
216→
217→  const topFrictionEntry = frictionItems[0];
218→  const topFriction = topFrictionEntry
219→    ? { category: topFrictionEntry.category, count: topFrictionEntry.count }
220→    : undefined;
221→
222→  const topPatternEntry = patternItems[0];
223→  const topPattern = topPatternEntry
224→    ? { label: topPatternEntry.category, frequency: topPatternEntry.count }
225→    : undefined;
226→
227→  return (
228→    <div className="space-y-4 p-4 lg:p-6">
229→      {/* Header */}
230→      <div className="flex flex-col gap-2 sm:flex-row sm:items-start sm:justify-between">
231→        <div>
232→          <h1 className="text-2xl font-bold">Patterns</h1>
233→          <p className="text-sm text-muted-foreground">
234→            Cross-session analysis — friction, wins, and working style
235→          </p>
236→          {/* Snapshot metadata line — shown when a reflection exists for this week */}
237→          {snapshotData?.snapshot && reflectResults && (
238→            <p className="text-xs text-muted-foreground mt-1">
239→              Generated {formatRelativeDate(snapshotData.snapshot.generatedAt)}
240→              {' · '}
241→              {snapshotData.snapshot.sessionCount} sessions analyzed
242→              {aggregation && aggregation.totalSessions > snapshotData.snapshot.sessionCount && (
243→                <> — <span className="text-amber-500">{aggregation.totalSessions - snapshotData.snapshot.sessionCount} new since</span></>
244→              )}
245→            </p>
246→          )}
247→        </div>
248→        <div className="flex flex-col items-end gap-2">
249→          {/* Week selector */}
250→          <WeekSelector
251→            currentWeek={currentWeek}
252→            weeks={weeks}
253→            onWeekChange={handleWeekChange}
254→          />
255→          <div className="flex items-center gap-2 flex-wrap justify-end">
256→            {projects.length > 1 && (
257→              <select
258→                value={selectedProject || ''}
259→                onChange={(e) => handleProjectChange(e.target.value || undefined)}
260→                className="h-8 rounded-md border bg-background px-2 text-xs"
261→              >
262→                <option value="">All Projects</option>
263→                {projects.map(p => (
264→                  <option key={p.id} value={p.id}>{p.name}</option>
265→                ))}
266→              </select>
267→            )}
268→            <Button
269→              onClick={handleGenerate}
270→              disabled={generating || !hasEnoughFacets}
271→              size="sm"
272→            >
273→              {generating ? (
274→                <><Loader2 className="h-4 w-4 mr-1.5 animate-spin" />Generating...</>
275→              ) : reflectResults ? (
276→                <><Sparkles className="h-4 w-4 mr-1.5" />Regenerate</>
277→              ) : (
278→                <><Sparkles className="h-4 w-4 mr-1.5" />Generate</>
279→              )}
280→            </Button>
281→          </div>
282→        </div>
283→      </div>
284→
285→      {/* Threshold gate */}
286→      {!hasEnoughFacets && aggregation && (
287→        <div className="flex items-start gap-3 rounded-lg border border-muted bg-muted/30 p-3">
288→          <AlertTriangle className="h-5 w-5 text-muted-foreground mt-0.5 shrink-0" />
289→          <div>
290→            {aggregation.totalAllSessions === 0 ? (
291→              <>
292→                <p className="text-sm font-medium">No sessions in this week</p>
293→                <p className="text-xs text-muted-foreground mt-1">
294→                  Navigate to a week with sessions using the arrows above.
295→                </p>
296→              </>
297→            ) : (
298→              <>
299→                <p className="text-sm font-medium">
300→                  Not enough analyzed sessions for pattern synthesis
301→                </p>
302→                <p className="text-xs text-muted-foreground mt-1">
303→                  Need at least 8 sessions with facets this week (currently {aggregation.totalSessions}).
304→                  Run session analysis to extract facets from more sessions.
305→                </p>
306→              </>
307→            )}
308→          </div>
309→        </div>
310→      )}
311→
312→      {/* Coverage warning */}
313→      {hasEnoughFacets && coverageRatio > 0 && coverageRatio < 0.5 && aggregation && (
314→        <div className="flex items-start gap-3 rounded-lg border border-amber-500/30 bg-amber-50 dark:bg-amber-950/20 p-3">
315→          <AlertTriangle className="h-5 w-5 text-amber-500 mt-0.5 shrink-0" />
316→          <div>
317→            <p className="text-sm font-medium">
318→              {aggregation.totalSessions} of {aggregation.totalAllSessions} sessions analyzed
319→            </p>
320→            <p className="text-xs text-muted-foreground mt-1">
321→              Results may not represent your full patterns. Analyze more sessions for better accuracy.
322→            </p>
323→          </div>
324→        </div>
325→      )}
326→
327→      {/* Outdated sessions alert — page-level so it's visible regardless of active tab */}
328→      {outdatedCount > 0 && (
329→        <Alert className="border-amber-500/30 bg-amber-50 dark:bg-amber-950/20">
330→          <AlertTriangle className="h-4 w-4 text-amber-500" />
331→          <AlertDescription className="text-xs text-amber-700 dark:text-amber-300">
332→            {outdatedCount} session{outdatedCount !== 1 ? 's have' : ' has'} outdated insight formats. Re-analyze them from the Session Insights page to improve pattern accuracy.
333→          </AlertDescription>
334→        </Alert>
335→      )}
336→
337→      {/* Generation progress */}
338→      {generating && (
339→        <Card>
340→          <CardContent className="py-4">
341→            <div className="flex items-center gap-3">
342→              <Loader2 className="h-4 w-4 animate-spin text-muted-foreground" />
343→              <span className="text-sm text-muted-foreground">{generationProgress}</span>
344→            </div>
345→          </CardContent>
346→        </Card>
347→      )}
348→
349→      {/* Week hero card — richer summary with stats, character distribution, streak, and outcomes */}
350→      <WeekAtAGlanceStrip
351→        tagline={tagline}
352→        totalSessions={aggregation?.totalSessions ?? 0}
353→        totalAllSessions={aggregation?.totalAllSessions ?? 0}
354→        outcomeDistribution={aggregation?.outcomeDistribution ?? {}}
355→        hasGenerated={!!reflectResults}
356→        characterDistribution={aggregation?.characterDistribution}
357→        streak={aggregation?.streak}
358→        rateLimitCount={aggregation?.rateLimitInfo?.count}
359→        rateLimitSessionsAffected={aggregation?.rateLimitInfo?.sessionsAffected}
360→      />
361→
362→      {/* 2-tab layout */}
363→      <Tabs defaultValue="insights">
364→        <TabsList variant="line" className="w-full justify-start border-b rounded-none px-0 h-auto pb-0">
365→          <TabsTrigger
366→            value="insights"
367→            className="flex items-center gap-1.5 pb-2.5 data-[state=active]:after:bg-blue-500 data-[state=active]:text-blue-600 dark:data-[state=active]:text-blue-400"
368→          >
369→            <Brain className="h-4 w-4" />
370→            Insights
371→          </TabsTrigger>
372→          <TabsTrigger
373→            value="artifacts"
374→            className="flex items-center gap-1.5 pb-2.5 data-[state=active]:after:bg-violet-500 data-[state=active]:text-violet-600 dark:data-[state=active]:text-violet-400"
375→          >
376→            <Shield className="h-4 w-4" />
377→            Artifacts
378→          </TabsTrigger>
379→        </TabsList>
380→
381→        {/* INSIGHTS TAB */}
382→        <TabsContent value="insights" className="mt-4 space-y-4">
383→          {/* Working style summary — borderless content, no Card wrapper */}
384→          {(reflectResults || (aggregation?.totalSessions ?? 0) > 0) && (
385→            <WorkingStyleHighlights
386→              narrative={narrative}
387→              totalSessions={aggregation?.totalSessions ?? 0}
388→              successCount={successCount}
389→              topCharacter={topCharacter}
390→              topFriction={topFriction}
391→              topPattern={topPattern}
392→            />
393→          )}
394→
395→          {/* Friction + Patterns — 50/50 grid */}
396→          <div className="grid gap-4 lg:grid-cols-2">
397→            {/* Friction Points — red left accent */}
398→            <Card className="border-l-2 border-red-400 dark:border-red-500">
399→              <CardHeader>
400→                <CardTitle className="flex items-center gap-2 text-base">
401→                  <AlertTriangle className="h-4 w-4 text-red-500 shrink-0" />
402→                  Friction Points
403→                </CardTitle>
404→                <CardDescription>Most common blockers across sessions — badge color indicates severity</CardDescription>
405→              </CardHeader>
406→              <CardContent>
407→                {frictionItems.length > 0 ? (
408→                  <CollapsibleCategoryList items={frictionItems} variant="friction" />
409→                ) : (
410→                  <p className="text-sm text-muted-foreground py-4 text-center">
411→                    No friction data yet. Analyze sessions to extract facets.
412→                  </p>
413→                )}
414→              </CardContent>
415→            </Card>
416→
417→            {/* Effective Patterns — emerald left accent */}
418→            <Card className="border-l-2 border-emerald-400 dark:border-emerald-500">
419→              <CardHeader>
420→                <CardTitle className="flex items-center gap-2 text-base">
421→                  <Sparkles className="h-4 w-4 text-emerald-500 shrink-0" />
422→                  Effective Patterns
423→                </CardTitle>
424→                <CardDescription>Techniques that work well across sessions</CardDescription>
425→              </CardHeader>
426→              <CardContent>
427→                {patternItems.length > 0 ? (
428→                  <CollapsibleCategoryList items={patternItems} variant="pattern" />
429→                ) : (
430→                  <p className="text-sm text-muted-foreground py-4 text-center">
431→                    No pattern data yet. Analyze sessions to extract facets.
432→                  </p>
433→                )}
434→              </CardContent>
435→            </Card>
436→          </div>
437→        </TabsContent>
438→
439→        {/* ARTIFACTS TAB */}
440→        <TabsContent value="artifacts" className="mt-4 space-y-4">
441→          {rulesSkillsResult ? (
442→            <>
443→              {/* CLAUDE.md Rules */}
444→              {Array.isArray(rulesSkillsResult.claudeMdRules) && (rulesSkillsResult.claudeMdRules as Array<{ rule: string; rationale: string; frictionSource: string }>).length > 0 && (
445→                <Card className="border-l-2 border-primary">
446→                  <CardHeader>
447→                    <CardTitle className="text-base">CLAUDE.md Rules</CardTitle>
448→                    <CardDescription>Add these to your AI assistant configuration</CardDescription>
449→                  </CardHeader>
450→                  <CardContent className="space-y-3">
451→                    {(rulesSkillsResult.claudeMdRules as Array<{ rule: string; rationale: string; frictionSource: string }>).map((r, i) => (
452→                      <div key={i} className="rounded-lg border p-3">
453→                        <div className="flex items-start justify-between gap-2">
454→                          <code className="text-sm font-mono flex-1">{r.rule}</code>
455→                          <Button
456→                            variant="ghost"
457→                            size="icon"
458→                            className="h-8 w-8 shrink-0"
459→                            onClick={() => handleCopy(r.rule, `rule-${i}`)}
460→                          >
461→                            {copiedKey === `rule-${i}` ? <Check className="h-3.5 w-3.5 text-green-500" /> : <Copy className="h-3.5 w-3.5" />}
462→                          </Button>
463→                        </div>
464→                        <p className="text-xs text-muted-foreground mt-2">{r.rationale}</p>
465→                        <div className="mt-2">
466→                          <Badge variant="secondary" className="text-xs">{r.frictionSource}</Badge>
467→                        </div>
468→                      </div>
469→                    ))}
470→                  </CardContent>
471→                </Card>
472→              )}
473→
474→              {/* Hook Configurations */}
475→              {Array.isArray(rulesSkillsResult.hookConfigs) && (rulesSkillsResult.hookConfigs as Array<{ event: string; command: string; rationale: string }>).length > 0 && (
476→                <Card className="border-l-2 border-primary">
477→                  <CardHeader>
478→                    <CardTitle className="text-base">Hook Configurations</CardTitle>
479→                    <CardDescription>Automation triggers</CardDescription>
480→                  </CardHeader>
481→                  <CardContent className="space-y-3">
482→                    {(rulesSkillsResult.hookConfigs as Array<{ event: string; command: string; rationale: string }>).map((h, i) => (
483→                      <div key={i} className="rounded-lg border p-3">
484→                        <div className="flex items-start justify-between gap-2">
485→                          <div>
486→                            <span className="text-xs font-mono bg-muted px-1.5 py-0.5 rounded">{h.event}</span>
487→                            <code className="block text-sm font-mono mt-2">{h.command}</code>
488→                          </div>
489→                          <Button
490→                            variant="ghost"
491→                            size="icon"
492→                            className="h-8 w-8 shrink-0"
493→                            onClick={() => handleCopy(h.command, `hook-${i}`)}
494→                          >
495→                            {copiedKey === `hook-${i}` ? <Check className="h-3.5 w-3.5 text-green-500" /> : <Copy className="h-3.5 w-3.5" />}
496→                          </Button>
497→                        </div>
498→                        <p className="text-xs text-muted-foreground mt-2">{h.rationale}</p>
499→                      </div>
500→                    ))}
501→                  </CardContent>
502→                </Card>
503→              )}
504→            </>
505→          ) : (
506→            /* Pattern Ingredients fallback — before generation */
507→            aggregation && (
508→              <Card>
509→                <CardHeader>
510→                  <CardTitle className="text-base">Pattern Ingredients</CardTitle>
511→                  <CardDescription>
512→                    {hasEnoughFacets
513→                      ? 'Click Generate to create rules and hooks from these patterns.'
514→                      : 'Analyze more sessions to unlock pattern synthesis.'}
515→                  </CardDescription>
516→                </CardHeader>
517→                <CardContent className="space-y-4">
518→                  {aggregation.frictionCategories.filter(fc => fc.count >= 3).length > 0 && (
519→                    <div>
520→                      <p className="text-xs font-medium text-muted-foreground mb-2">Recurring friction (3+ occurrences):</p>
521→                      <ul className="space-y-1">
522→                        {aggregation.frictionCategories.filter(fc => fc.count >= 3).map((fc, i) => (
523→                          <li key={i} className="text-sm flex items-center gap-2">
524→                            <span className="text-xs font-mono text-muted-foreground">{fc.count}x</span>
525→                            {fc.category}
526→                          </li>
527→                        ))}
528→                      </ul>
529→                    </div>
530→                  )}
531→                  {aggregation.effectivePatterns.filter(ep => ep.frequency >= 2).length > 0 && (
532→                    <div>
533→                      <p className="text-xs font-medium text-muted-foreground mb-2">Effective patterns (2+ occurrences):</p>
534→                      <ul className="space-y-1">
535→                        {aggregation.effectivePatterns.filter(ep => ep.frequency >= 2).map((ep, i) => (
