 40→// Detect the dominant source tool from the database to target artifact generation.
 41→function detectTargetTool(db: ReturnType<typeof getDb>): string {
 42→  const row = db.prepare(
 43→    `SELECT source_tool, COUNT(*) as count FROM sessions WHERE deleted_at IS NULL GROUP BY source_tool ORDER BY count DESC LIMIT 1`
 44→  ).get() as { source_tool: string; count: number } | undefined;
 45→  return row?.source_tool || 'claude-code';
