  1→import { Hono } from 'hono';
  2→import { streamSSE } from 'hono/streaming';
  3→import { getDb } from '@code-insights/cli/db/client';
  4→import { jsonrepair } from 'jsonrepair';
  5→import { createLLMClient } from '../llm/client.js';
  6→import { requireLLM } from './route-helpers.js';
  7→import { extractJsonPayload } from '../llm/response-parsers.js';
  8→import {
  9→  FRICTION_WINS_SYSTEM_PROMPT,
 10→  generateFrictionWinsPrompt,
 11→  RULES_SKILLS_SYSTEM_PROMPT,
 12→  generateRulesSkillsPrompt,
 13→  WORKING_STYLE_SYSTEM_PROMPT,
 14→  generateWorkingStylePrompt,
 15→} from '../llm/reflect-prompts.js';
 16→import { buildWhereClause, buildPeriodFilter, parseIsoWeek, formatIsoWeek, getAggregatedData } from './shared-aggregation.js';
 17→import type { ReflectSection } from '@code-insights/cli/types';
 18→
 19→const app = new Hono();
 20→
 21→const MIN_FACETS_FOR_REFLECT = 8;
 22→
 23→const ALL_SECTIONS: ReflectSection[] = ['friction-wins', 'rules-skills', 'working-style'];
 24→
 25→// Parse LLM JSON response wrapped in <json>...</json> tags with jsonrepair fallback.
 26→function parseLLMJson<T>(response: string): T | null {
 27→  const payload = extractJsonPayload(response);
 28→  if (!payload) return null;
 29→  try {
 30→    return JSON.parse(payload) as T;
 31→  } catch {
 32→    try {
 33→      return JSON.parse(jsonrepair(payload)) as T;
 34→    } catch {
 35→      return null;
 36→    }
 37→  }
 38→}
