 48→// POST /api/reflect/generate
 49→// Body: { sections?: ReflectSection[], period?: string, project?: string, source?: string }
 50→// SSE endpoint: aggregates facets in code, then calls synthesis prompts for each section.
 51→// Streams progress events so the UI can show phase-by-phase progress.
 52→app.post('/generate', requireLLM(), async (c) => {
 53→
 54→  const body = await c.req.json<{
 55→    sections?: ReflectSection[];
 56→    period?: string;
 57→    project?: string;
 58→    source?: string;
 59→  }>();
 60→
 61→  const sections = body.sections && body.sections.length > 0 ? body.sections : ALL_SECTIONS;
 62→  const period = body.period || '30d';
 63→
 64→  const db = getDb();
 65→  const { where, params } = buildWhereClause(period, body.project, body.source);
 66→
 67→  return streamSSE(c, async (stream) => {
 68→    const abortSignal = c.req.raw.signal;
 69→
 70→    try {
 71→      await stream.writeSSE({
 72→        event: 'progress',
 73→        data: JSON.stringify({ phase: 'aggregating', message: 'Aggregating facets...' }),
 74→      });
 75→
 76→      const aggregated = getAggregatedData(db, where, params, body.project, body.source);
 77→
 78→      if (aggregated.totalSessions === 0) {
 79→        await stream.writeSSE({
 80→          event: 'error',
 81→          data: JSON.stringify({ error: 'No sessions with facets found. Run analysis first.' }),
 82→        });
 83→        return;
 84→      }
 85→
 86→      if (aggregated.totalSessions < MIN_FACETS_FOR_REFLECT) {
 87→        await stream.writeSSE({
 88→          event: 'error',
 89→          data: JSON.stringify({
 90→            error: `Need at least ${MIN_FACETS_FOR_REFLECT} analyzed sessions for meaningful pattern synthesis. Currently have ${aggregated.totalSessions}. Run session analysis on more sessions first.`,
 91→            code: 'INSUFFICIENT_FACETS',
 92→            current: aggregated.totalSessions,
 93→            required: MIN_FACETS_FOR_REFLECT,
 94→          }),
 95→        });
 96→        return;
 97→      }
 98→
 99→      const client = createLLMClient();
100→      const results: Record<string, unknown> = {};
101→      const targetTool = detectTargetTool(db);
102→
103→      for (const section of sections) {
104→        if (abortSignal.aborted) break;
105→
106→        await stream.writeSSE({
107→          event: 'progress',
108→          data: JSON.stringify({ phase: 'synthesizing', section, message: `Generating ${section}...` }),
109→        });
110→
111→        if (section === 'friction-wins') {
112→          const prompt = generateFrictionWinsPrompt({
113→            frictionCategories: aggregated.frictionCategories,
114→            effectivePatterns: aggregated.effectivePatterns,
115→            totalSessions: aggregated.totalSessions,
116→            period,
117→            pqSignals: (aggregated.pqDeficits.length || aggregated.pqStrengths.length)
118→              ? { deficits: aggregated.pqDeficits, strengths: aggregated.pqStrengths }
119→              : undefined,
120→          });
121→          const response = await client.chat([
122→            { role: 'system', content: FRICTION_WINS_SYSTEM_PROMPT },
123→            { role: 'user', content: prompt },
124→          ], { signal: abortSignal });
125→          const parsed = parseLLMJson(response.content);
126→          results['friction-wins'] = {
127→            section: 'friction-wins',
128→            ...(parsed ?? {}),
129→            frictionCategories: aggregated.frictionCategories,
130→            effectivePatterns: aggregated.effectivePatterns,
131→            pqDeficits: aggregated.pqDeficits,
132→            pqStrengths: aggregated.pqStrengths,
133→            generatedAt: new Date().toISOString(),
134→          };
135→        } else if (section === 'rules-skills') {
136→          // Only include patterns with sufficient occurrence counts for actionable artifacts
137→          const recurringFriction = aggregated.frictionCategories.filter(fc => fc.count >= 3);
138→          const recurringPatterns = aggregated.effectivePatterns.filter(ep => ep.frequency >= 2);
139→          const prompt = generateRulesSkillsPrompt({
140→            recurringFriction,
141→            effectivePatterns: recurringPatterns,
142→            targetTool,
143→          });
144→          const response = await client.chat([
145→            { role: 'system', content: RULES_SKILLS_SYSTEM_PROMPT },
146→            { role: 'user', content: prompt },
147→          ], { signal: abortSignal });
148→          const parsed = parseLLMJson(response.content);
149→          results['rules-skills'] = {
150→            section: 'rules-skills',
151→            ...(parsed ?? {}),
152→            targetTool,
153→            generatedAt: new Date().toISOString(),
154→          };
155→        } else if (section === 'working-style') {
156→          const prompt = generateWorkingStylePrompt({
157→            workflowDistribution: aggregated.workflowDistribution,
158→            outcomeDistribution: aggregated.outcomeDistribution,
159→            characterDistribution: aggregated.characterDistribution,
160→            totalSessions: aggregated.totalSessions,
161→            period,
162→            frictionFrequency: aggregated.frictionTotal,
163→          });
164→          const response = await client.chat([
165→            { role: 'system', content: WORKING_STYLE_SYSTEM_PROMPT },
166→            { role: 'user', content: prompt },
167→          ], { signal: abortSignal });
168→          const parsed = parseLLMJson(response.content);
169→          // Sanitize tagline: must be a string ≤40 chars. Non-string LLM outputs
170→          // (object, array, number) are normalized to undefined so they don't
171→          // corrupt the snapshot blob stored in SQLite.
172→          const rawTagline = parsed && (parsed as Record<string, unknown>)['tagline'];
173→          const tagline = typeof rawTagline === 'string'
174→            ? rawTagline.slice(0, 40)
175→            : undefined;
176→          results['working-style'] = {
177→            section: 'working-style',
178→            ...(parsed ?? {}),
179→            tagline,
180→            workflowDistribution: aggregated.workflowDistribution,
181→            outcomeDistribution: aggregated.outcomeDistribution,
182→            characterDistribution: aggregated.characterDistribution,
183→            generatedAt: new Date().toISOString(),
184→          };
185→        }
186→      }
187→
188→      // Only save snapshot if the request was not aborted mid-generation.
189→      // Saving partial results would cause stale/incomplete data to auto-load on next visit.
190→      if (!c.req.raw.signal.aborted) {
191→        // For ISO week periods, use the exact week boundaries as window metadata.
192→        // This ensures the snapshot metadata accurately reflects the week it covers.
193→        const isoWeekBounds = parseIsoWeek(period);
194→        const windowStart = isoWeekBounds
195→          ? isoWeekBounds.start.toISOString()
196→          : buildPeriodFilter(period);
197→        const windowEnd = isoWeekBounds
198→          ? isoWeekBounds.end.toISOString()
199→          : new Date().toISOString();
200→        const projectKey = body.project || '__all__';
201→
202→        db.prepare(`
203→          INSERT INTO reflect_snapshots (period, project_id, results_json, generated_at, window_start, window_end, session_count, facet_count)
204→          VALUES (?, ?, ?, ?, ?, ?, ?, ?)
205→          ON CONFLICT(period, project_id) DO UPDATE SET
206→            results_json = excluded.results_json,
207→            generated_at = excluded.generated_at,
208→            window_start = excluded.window_start,
209→            window_end = excluded.window_end,
210→            session_count = excluded.session_count,
211→            facet_count = excluded.facet_count
212→        `).run(
213→          period,
214→          projectKey,
215→          JSON.stringify(results),
216→          new Date().toISOString(),
217→          windowStart,
218→          windowEnd,
219→          aggregated.totalSessions,
220→          aggregated.frictionTotal
221→        );
222→      }
223→
224→      await stream.writeSSE({
225→        event: 'complete',
226→        data: JSON.stringify({ results }),
227→      });
228→    } catch (err) {
229→      const message = err instanceof Error ? err.message : 'Unknown error';
230→      await stream.writeSSE({
231→        event: 'error',
232→        data: JSON.stringify({ error: message }),
233→      }).catch(() => {});
234→    }
235→  });
236→});
