253→// GET /api/reflect/weeks
254→// Returns all ISO weeks from the earliest session through the current week, with snapshot status.
255→// Used by the WeekSelector component to show which weeks have reflections.
256→// Week list is data-driven (not capped at 8) so users with long history can navigate all weeks.
257→app.get('/weeks', (c) => {
258→  const db = getDb();
259→  const project = c.req.query('project');
260→
261→  const projectCondition = project ? 'AND project_id = ?' : '';
262→  const projectParams: string[] = project ? [project] : [];
263→
264→  // Find the earliest session to determine the full week range.
265→  // If no sessions exist, return empty array.
266→  const earliestRow = db.prepare(`
267→    SELECT MIN(started_at) as earliest
268→    FROM sessions
269→    WHERE deleted_at IS NULL
270→      ${projectCondition}
271→  `).get(...projectParams) as { earliest: string | null } | undefined;
272→
273→  if (!earliestRow?.earliest) {
274→    return c.json({ weeks: [] });
275→  }
276→
277→  // Compute the UTC midnight of the Monday of the current ISO week.
278→  // Truncating to midnight ensures the while-loop comparison is stable
279→  // regardless of the time-of-day component in started_at values.
280→  const now = new Date();
281→  const nowDay = now.getUTCDay(); // 0=Sun
282→  const daysToMonday = nowDay === 0 ? 6 : nowDay - 1;
283→  const thisMondayMs = Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate()) - daysToMonday * 86400000;
284→
285→  // Compute the UTC midnight of the Monday of the earliest session's ISO week.
286→  const earliestDate = new Date(earliestRow.earliest);
287→  const earliestDay = earliestDate.getUTCDay();
288→  const daysToEarliestMonday = earliestDay === 0 ? 6 : earliestDay - 1;
289→  const earliestMondayMs = Date.UTC(earliestDate.getUTCFullYear(), earliestDate.getUTCMonth(), earliestDate.getUTCDate()) - daysToEarliestMonday * 86400000;
290→
291→  // Generate all weeks from earliest through current (most recent first).
292→  // Cap at 520 weeks (~10 years) to stay under SQLite's 999 bind-variable limit
293→  // for the snapshot IN (...) query (each week uses 1 placeholder + 1 for project_id).
294→  const MAX_WEEKS = 520;
295→  type WeekEntry = { week: string; start: string; end: string };
296→  const weekEntries: WeekEntry[] = [];
297→  let weekMondayMs = thisMondayMs;
298→  while (weekMondayMs >= earliestMondayMs && weekEntries.length < MAX_WEEKS) {
299→    const weekMonday = new Date(weekMondayMs);
300→    const week = formatIsoWeek(weekMonday);
301→    const bounds = parseIsoWeek(week)!;
302→    weekEntries.push({ week, start: bounds.start.toISOString(), end: bounds.end.toISOString() });
303→    weekMondayMs -= 7 * 86400000;
304→  }
305→
306→  const projectKey = project || '__all__';
307→
308→  // Query 1: session counts per ISO week using GROUP BY.
309→  // The Thursday trick: 'weekday 4' advances to the ISO week's Thursday (or stays if already
310→  // Thursday), then '-3 days' gives that week's Monday. This handles all 7 days correctly —
311→  // unlike 'weekday 1, -7 days' which overshoots by one week for sessions starting on Monday.
312→  // Returns one row per week that has sessions — O(sessions), not O(weeks).
313→  const rangeStart = weekEntries[weekEntries.length - 1].start;
314→  const rangeEnd = weekEntries[0].end;
315→
316→  const sessionCountRaw = db.prepare(`
317→    SELECT
318→      date(s.started_at, 'weekday 4', '-3 days') as week_monday,
319→      COUNT(*) as cnt
320→    FROM sessions s
321→    WHERE s.deleted_at IS NULL
322→      AND s.started_at >= ?
323→      AND s.started_at < ?
324→      ${projectCondition}
325→    GROUP BY week_monday
326→  `).all(
327→    rangeStart,
328→    rangeEnd,
329→    ...projectParams
330→  ) as Array<{ week_monday: string; cnt: number }>;
331→
332→  // Build a map from ISO week string -> session count.
333→  // week_monday is a YYYY-MM-DD string (SQLite date()); parse it and derive the ISO week string.
334→  const sessionCountMap = new Map<string, number>();
335→  for (const row of sessionCountRaw) {
336→    const monday = new Date(row.week_monday + 'T00:00:00Z');
337→    const weekStr = formatIsoWeek(monday);
338→    // Accumulate in case formatIsoWeek maps two slightly-different Mondays to the same week
339→    sessionCountMap.set(weekStr, (sessionCountMap.get(weekStr) ?? 0) + row.cnt);
340→  }
341→
342→  // Query 2: all snapshots for these weeks in one query
343→  const weekPlaceholders = weekEntries.map(() => '?').join(', ');
344→  const snapshotRows = db.prepare(`
345→    SELECT period, generated_at
346→    FROM reflect_snapshots
347→    WHERE period IN (${weekPlaceholders}) AND project_id = ?
348→  `).all(...weekEntries.map(e => e.week), projectKey) as Array<{ period: string; generated_at: string }>;
349→
350→  const snapshotMap = new Map(snapshotRows.map(r => [r.period, r.generated_at]));
351→
352→  const weeks = weekEntries.map((entry) => ({
353→    week: entry.week,
354→    sessionCount: sessionCountMap.get(entry.week) ?? 0,
355→    hasSnapshot: snapshotMap.has(entry.week),
356→    generatedAt: snapshotMap.get(entry.week) ?? null,
357→  }));
358→
359→  return c.json({ weeks });
360→});
