213→export async function exportGenerateStream(
214→  params: ExportGenerateRequest,
215→  signal?: AbortSignal
216→): Promise<Response> {
217→  const q = new URLSearchParams();
218→  q.set('scope', params.scope);
219→  if (params.projectId) q.set('projectId', params.projectId);
220→  q.set('format', params.format);
221→  if (params.depth) q.set('depth', params.depth);
