223→  const res = await fetch(`${BASE}/export/generate/stream?${q.toString()}`, { signal });
224→  if (!res.ok) {
225→    const text = await res.text().catch(() => res.statusText);
226→    throw new Error(`Export stream failed ${res.status}: ${text}`);
227→  }
228→  return res;
229→}
