 1→import { createContext, useContext, useEffect, useState, type ReactNode } from 'react';
 2→
 3→type Theme = 'light' | 'dark' | 'system';
 4→
 5→interface ThemeContextValue {
 6→  theme: Theme;
 7→  resolvedTheme: 'light' | 'dark';
 8→  setTheme: (theme: Theme) => void;
 9→}
10→
11→const ThemeContext = createContext<ThemeContextValue | null>(null);
12→
13→const STORAGE_KEY = 'code-insights-theme';
14→
15→function getSystemTheme(): 'light' | 'dark' {
16→  return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
17→}
18→
19→function applyTheme(resolved: 'light' | 'dark') {
20→  const root = document.documentElement;
21→  root.classList.remove('light', 'dark');
22→  root.classList.add(resolved);
23→}
24→
25→interface ThemeProviderProps {
26→  children: ReactNode;
27→  defaultTheme?: Theme;
28→}
29→
30→export function ThemeProvider({ children, defaultTheme = 'system' }: ThemeProviderProps) {
31→  const [theme, setThemeState] = useState<Theme>(() => {
32→    try {
33→      const stored = localStorage.getItem(STORAGE_KEY);
34→      if (stored === 'light' || stored === 'dark' || stored === 'system') return stored;
35→      return defaultTheme;
36→    } catch {
37→      return defaultTheme;
38→    }
39→  });
40→
41→  const resolvedTheme: 'light' | 'dark' = theme === 'system' ? getSystemTheme() : theme;
42→
43→  useEffect(() => {
44→    applyTheme(resolvedTheme);
45→  }, [resolvedTheme]);
46→
47→  // Listen for system preference changes when theme === 'system'
48→  useEffect(() => {
49→    if (theme !== 'system') return;
50→    const mq = window.matchMedia('(prefers-color-scheme: dark)');
51→    const handler = () => applyTheme(mq.matches ? 'dark' : 'light');
52→    mq.addEventListener('change', handler);
53→    return () => mq.removeEventListener('change', handler);
54→  }, [theme]);
55→
56→  function setTheme(next: Theme) {
57→    setThemeState(next);
58→    try {
59→      localStorage.setItem(STORAGE_KEY, next);
60→    } catch {
61→      // localStorage unavailable (e.g. private browsing restrictions)
62→    }
63→  }
64→
65→  return (
66→    <ThemeContext.Provider value={{ theme, resolvedTheme, setTheme }}>
67→      {children}
68→    </ThemeContext.Provider>
69→  );
70→}
71→
72→export function useTheme(): ThemeContextValue {
73→  const ctx = useContext(ThemeContext);
74→  if (!ctx) throw new Error('useTheme must be used inside ThemeProvider');
75→  return ctx;
76→}
