 10→
 11→interface WorkingStyleHighlightsProps {
 12→  narrative?: string;
 13→  totalSessions: number;
 14→  successCount: number;
 15→  topCharacter?: { name: string; percentage: number };
 16→  topFriction?: { category: string; count: number };
 17→  topPattern?: { label: string; frequency: number };
 18→}
 19→
 20→function formatCharacterName(raw: string): string {
 21→  return raw.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase());
 22→}
 23→
 24→export function WorkingStyleHighlights({
 25→  narrative,
 26→  totalSessions,
 27→  successCount,
 28→  topCharacter,
 29→  topFriction,
 30→  topPattern,
 31→}: WorkingStyleHighlightsProps) {
 32→  const [showNarrative, setShowNarrative] = useState(false);
 33→
 34→  // Build pill data from available props
 35→  const pills: Array<{
 36→    icon: React.ReactNode;
 37→    value: string;
 38→    sublabel: string;
 39→    className: string;
 40→  }> = [];
 41→
 42→  if (totalSessions > 0) {
 43→    pills.push({
 44→      icon: <CheckCircle2 className="h-4 w-4 text-emerald-500" />,
 45→      value: `${successCount}/${totalSessions}`,
 46→      sublabel: 'high-quality',
 47→      className: 'bg-emerald-500/10 border-emerald-500/20',
 48→    });
 49→  }
 50→
 51→  if (topFriction) {
 52→    pills.push({
 53→      icon: <AlertTriangle className="h-4 w-4 text-red-500" />,
 54→      value: `${topFriction.count}x`,
 55→      sublabel: topFriction.category,
 56→      className: 'bg-red-500/10 border-red-500/20',
 57→    });
 58→  }
 59→
 60→  if (topPattern) {
 61→    pills.push({
 62→      icon: <Sparkles className="h-4 w-4 text-blue-500" />,
 63→      value: `${topPattern.frequency}x`,
 64→      sublabel: topPattern.label,
 65→      className: 'bg-blue-500/10 border-blue-500/20',
 66→    });
 67→  }
 68→
 69→  if (topCharacter) {
 70→    const charColorClass = SESSION_CHARACTER_COLORS[topCharacter.name] ?? 'bg-muted text-muted-foreground border-border';
 71→    pills.push({
 72→      icon: <User className="h-4 w-4" />,
 73→      value: `${topCharacter.percentage}%`,
 74→      sublabel: formatCharacterName(topCharacter.name),
 75→      // Use the character color classes but override bg/border via className merge
 76→      className: charColorClass,
 77→    });
 78→  }
 79→
 80→  if (pills.length === 0) {
 81→    return null;
 82→  }
 83→
 84→  return (
 85→    <div className="space-y-3">
 86→      {/* Stat pills row */}
 87→      <div className="flex flex-wrap gap-2">
 88→        {pills.map((pill, i) => (
 89→          <div
 90→            key={i}
 91→            className={`flex items-center gap-2 rounded-lg border px-3 py-2 ${pill.className}`}
 92→          >
 93→            {pill.icon}
 94→            <div className="min-w-0">
 95→              <div className="text-sm font-semibold leading-tight tabular-nums">{pill.value}</div>
 96→              <div className="text-xs text-muted-foreground leading-tight truncate max-w-[120px]">{pill.sublabel}</div>
 97→            </div>
 98→          </div>
 99→        ))}
100→      </div>
101→
102→      {/* Expandable LLM narrative — only shown when it exists */}
103→      {narrative && (
104→        <div>
105→          <button
106→            type="button"
107→            className="flex items-center gap-1 text-xs text-muted-foreground hover:text-foreground transition-colors"
108→            onClick={() => setShowNarrative(prev => !prev)}
109→          >
110→            {showNarrative ? (
111→              <><ChevronUp className="h-3.5 w-3.5" />Hide full analysis</>
112→            ) : (
113→              <><ChevronDown className="h-3.5 w-3.5" />Show full analysis</>
114→            )}
115→          </button>
116→
117→          {showNarrative && (
118→            <p className="mt-2 text-sm leading-relaxed whitespace-pre-wrap text-muted-foreground">
119→              {narrative}
120→            </p>
121→          )}
122→        </div>
123→      )}
124→    </div>
125→  );
126→}
