          style={{
            position: 'absolute',
            inset: 0,
            background: 'linear-gradient(135deg, #0f0f23 0%, #1a1a3e 100%)',
          }}
        />

        {/* Radial glow accents — rgba() instead of 8-digit hex for html-to-image compat */}
        <div
          style={{
            position: 'absolute',
            top: '-80px',
            left: '-80px',
            width: '400px',
            height: '400px',
            borderRadius: '50%',
            background: 'radial-gradient(circle, rgba(59,130,246,0.13) 0%, transparent 70%)',
            pointerEvents: 'none',
          }}
        />
        <div
          style={{
            position: 'absolute',
            bottom: '-100px',
            right: '-80px',
            width: '500px',
            height: '500px',
            borderRadius: '50%',
            background: 'radial-gradient(circle, rgba(168,85,247,0.09) 0%, transparent 70%)',
            pointerEvents: 'none',
          }}
        />

        {/* Content area */}
        <div
          style={{
            position: 'relative',
            padding: '40px',
            height: '100%',
            boxSizing: 'border-box',
            display: 'flex',
            flexDirection: 'column',
          }}
        >
          {/* ── Top: Logo + app name ── */}
          <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '18px' }}>
            {/* App logo SVG */}
            <svg width="28" height="28" viewBox="0 0 28 28" fill="none">
              <rect width="28" height="28" rx="7" fill="#3b82f6" />
              <path d="M8 10h12M8 14h8M8 18h10" stroke="white" strokeWidth="2" strokeLinecap="round" />
            </svg>
            <span
              style={{
                fontSize: '13px',
                color: '#a0a0b8',
                letterSpacing: '0.1em',
                textTransform: 'uppercase',
                fontWeight: 600,
              }}
            >
              Code Insights
            </span>
          </div>

          {/* ── Tagline ── */}
          {/* Solid color instead of background-clip:text gradient — html-to-image cannot serialize gradient text */}
          <p
            style={{
              fontSize: '42px',
              fontWeight: 700,
              lineHeight: 1.15,
              margin: '0 0 24px 0',
              color: '#93b4fc',
              maxWidth: '900px',
            }}
          >
            {tagline}
          </p>

          {/* ── Stat boxes ── */}
          <div style={{ display: 'flex', gap: '12px', marginBottom: '24px' }}>
            {[
              { value: abbreviateCount(totalSessions), label: 'Sessions' },
              { value: streak > 0 ? `${streak}d` : '—', label: 'Streak' },
              { value: outcomeTotal > 0 ? `${successRate}%` : '—', label: 'Success' },
            ].map(({ value, label }) => (
              <div
                key={label}
                style={{
                  width: '140px',
                  height: '64px',
                  borderRadius: '8px',
                  backgroundColor: 'rgba(255,255,255,0.024)',
                  border: '1px solid rgba(255,255,255,0.063)',
                  padding: '12px 16px',
                  boxSizing: 'border-box',
                  display: 'flex',
                  flexDirection: 'column',
                  justifyContent: 'center',
                }}
              >
                <span style={{ fontSize: '28px', fontWeight: 700, color: '#f1f5f9', lineHeight: 1 }}>
                  {value}
                </span>
                <span
                  style={{
                    fontSize: '11px',
                    color: '#64748b',
                    textTransform: 'uppercase',
                    letterSpacing: '0.05em',
                    marginTop: '2px',
                  }}
                >
                  {label}
                </span>
              </div>
            ))}
          </div>

          {/* ── Middle zone: LEFT (tools + milestones) / RIGHT (donut) ── */}
          <div style={{ display: 'flex', flex: 1, gap: '24px', alignItems: 'flex-start' }}>
            {/* LEFT — 55% */}
            <div style={{ flex: '0 0 55%', display: 'flex', flexDirection: 'column', gap: '12px' }}>
              {/* Tool pills */}
              {hasTools && (
                <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px' }}>
                  {sourceTools.map((tool) => {
                    const colors = SOURCE_TOOL_PILL_COLORS[tool] ?? {
                      bg: '#1e293b', text: '#94a3b8', border: 'rgba(148,163,184,0.3)',
                    };
                    return (
                      <span
