  1→/**
  2→ * ShareCardDonut — pure inline SVG donut chart for the shareable card export.
  3→ *
  4→ * Uses <circle> stroke-dasharray/stroke-dashoffset for segments.
  5→ * Recharts is NOT used here — html-to-image has canvas compatibility issues
  6→ * with foreign object elements that Recharts relies on.
  7→ * All colors are hardcoded hex literals.
  8→ */
  9→
 10→interface DonutDataItem {
 11→  label: string;
 12→  value: number;
 13→  color: string;
 14→}
 15→
 16→interface ShareCardDonutProps {
 17→  data: DonutDataItem[];
 18→  size: number;
 19→  strokeWidth: number;
 20→}
 21→
 22→export function ShareCardDonut({ data, size, strokeWidth }: ShareCardDonutProps) {
 23→  const total = data.reduce((s, d) => s + d.value, 0);
 24→  if (total === 0) return null;
 25→
 26→  const r = (size - strokeWidth) / 2;
 27→  const cx = size / 2;
 28→  const cy = size / 2;
 29→  const circumference = 2 * Math.PI * r;
 30→
 31→  // Build segments with cumulative offset
 32→  let cumulativeOffset = 0;
 33→  // SVG starts at 3 o'clock; rotate -90deg to start from 12 o'clock
 34→  const segments = data.map((d) => {
 35→    const dashLen = (d.value / total) * circumference;
 36→    const dashGap = circumference - dashLen;
 37→    const offset = circumference - cumulativeOffset;
 38→    cumulativeOffset += dashLen;
 39→    return { ...d, dashLen, dashGap, offset };
 40→  });
 41→
 42→  return (
 43→    <div style={{ display: 'flex', alignItems: 'center', gap: '14px' }}>
 44→      {/* Donut */}
 45→      <svg
 46→        width={size}
 47→        height={size}
 48→        style={{ transform: 'rotate(-90deg)', flexShrink: 0 }}
 49→      >
 50→        {/* Track */}
 51→        <circle
 52→          cx={cx}
 53→          cy={cy}
 54→          r={r}
 55→          fill="none"
 56→          stroke="rgba(255,255,255,0.07)"
 57→          strokeWidth={strokeWidth}
 58→        />
 59→        {/* Segments */}
 60→        {segments.map((seg, i) => (
 61→          <circle
 62→            key={i}
 63→            cx={cx}
 64→            cy={cy}
 65→            r={r}
 66→            fill="none"
 67→            stroke={seg.color}
 68→            strokeWidth={strokeWidth}
 69→            strokeDasharray={`${seg.dashLen} ${seg.dashGap}`}
 70→            strokeDashoffset={seg.offset}
 71→            strokeLinecap="butt"
 72→          />
 73→        ))}
 74→      </svg>
 75→
 76→      {/* Legend */}
 77→      <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
 78→        {data.map((d, i) => {
 79→          const pct = Math.round((d.value / total) * 100);
 80→          return (
 81→            <div key={i} style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
 82→              <div
 83→                style={{
 84→                  width: '8px',
 85→                  height: '8px',
 86→                  borderRadius: '50%',
 87→                  backgroundColor: d.color,
 88→                  flexShrink: 0,
 89→                }}
 90→              />
 91→              <span style={{ fontSize: '11px', color: '#94a3b8', whiteSpace: 'nowrap' }}>
 92→                {d.label}
 93→              </span>
 94→              <span style={{ fontSize: '11px', color: '#475569', marginLeft: '2px' }}>
 95→                {pct}%
 96→              </span>
 97→            </div>
 98→          );
 99→        })}
100→      </div>
101→    </div>
102→  );
103→}
