 50→/**
 51→ * Derive month + year label from an ISO week string (e.g. "2026-W11" → "Mar 2026").
 52→ * Uses the Monday of that week — avoids showing the wrong month when viewing historical weeks.
 53→ */
 54→function getMonthYearFromWeek(isoWeek: string): string {
 55→  const match = /^(\d{4})-W(\d{2})$/.exec(isoWeek);
 56→  if (!match) {
 57→    return new Date().toLocaleDateString('en-US', { month: 'short', year: 'numeric' });
 58→  }
 59→  const year = parseInt(match[1], 10);
 60→  const week = parseInt(match[2], 10);
 61→  // Find Monday of ISO week 1: Jan 4 is always in week 1
 62→  const jan4 = new Date(Date.UTC(year, 0, 4));
 63→  const jan4Day = jan4.getUTCDay();
 64→  const daysToMonday = jan4Day === 0 ? 6 : jan4Day - 1;
 65→  const week1Monday = new Date(jan4.getTime() - daysToMonday * 86400000);
 66→  const weekMonday = new Date(week1Monday.getTime() + (week - 1) * 7 * 86400000);
 67→  return weekMonday.toLocaleDateString('en-US', { month: 'short', year: 'numeric', timeZone: 'UTC' });
 68→}
