                  style={{
                    fontSize: '11px',
                    color: '#64748b',
                    textTransform: 'uppercase',
                    letterSpacing: '0.05em',
                    marginTop: '2px',
                  }}
                >
                  {label}
                </span>
              </div>
            ))}
          </div>

          {/* ── Middle zone: LEFT (tools + milestones) / RIGHT (donut) ── */}
          <div style={{ display: 'flex', flex: 1, gap: '24px', alignItems: 'flex-start' }}>
            {/* LEFT — 55% */}
            <div style={{ flex: '0 0 55%', display: 'flex', flexDirection: 'column', gap: '12px' }}>
              {/* Tool pills */}
              {hasTools && (
                <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px' }}>
                  {sourceTools.map((tool) => {
                    const colors = SOURCE_TOOL_PILL_COLORS[tool] ?? {
                      bg: '#1e293b', text: '#94a3b8', border: 'rgba(148,163,184,0.3)',
                    };
                    return (
                      <span
                        key={tool}
                        style={{
                          display: 'inline-flex',
                          alignItems: 'center',
                          padding: '4px 10px',
                          borderRadius: '999px',
                          fontSize: '12px',
                          fontWeight: 500,
                          backgroundColor: colors.bg,
                          color: colors.text,
                          border: `1px solid ${colors.border}`,
                        }}
                      >
                        {SOURCE_TOOL_DISPLAY_NAMES[tool] ?? tool}
                      </span>
                    );
                  })}
                </div>
              )}

              {/* Milestone pills */}
              {hasMilestones && (
                <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px' }}>
                  {milestones.map((m, i) => (
                    <span
                      key={i}
                      style={{
                        display: 'inline-flex',
                        alignItems: 'center',
                        gap: '5px',
                        padding: '4px 10px',
                        borderRadius: '999px',
                        fontSize: '12px',
                        fontWeight: 500,
                        backgroundColor: 'rgba(255,255,255,0.04)',
                        color: '#94a3b8',
                        border: '1px solid rgba(255,255,255,0.12)',
                      }}
                    >
                      <span style={{ color: m.iconColor }}>{m.icon}</span>
                      {m.label}
                    </span>
                  ))}
                </div>
              )}
            </div>

            {/* RIGHT — 45% */}
            {hasDonut && (
              <div style={{ flex: '0 0 45%', display: 'flex', justifyContent: 'flex-end' }}>
                <ShareCardDonut data={donutData} size={150} strokeWidth={22} />
              </div>
            )}
          </div>

          {/* ── Footer ── */}
          <div style={{ marginTop: 'auto', paddingTop: '16px' }}>
            <div style={{ height: '1px', backgroundColor: '#ffffff12', marginBottom: '14px' }} />
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                <svg width="18" height="18" viewBox="0 0 28 28" fill="none">
                  <rect width="28" height="28" rx="7" fill="#3b82f6" />
                  <path d="M8 10h12M8 14h8M8 18h10" stroke="white" strokeWidth="2" strokeLinecap="round" />
                </svg>
                <span style={{ fontSize: '13px', color: '#64748b' }}>code-insights.app</span>
              </div>
              <span style={{ fontSize: '12px', color: '#475569' }}>
                Patterns · {getMonthYearFromWeek(currentWeek)}
              </span>
            </div>
          </div>
        </div>
      </div>
    );
  }
);

/**
 * ShareCardDonut — pure inline SVG donut chart for the shareable card export.
 *
 * Uses <circle> stroke-dasharray/stroke-dashoffset for segments.
 * Recharts is NOT used here — html-to-image has canvas compatibility issues
 * with foreign object elements that Recharts relies on.
 * All colors are hardcoded hex literals.
 */

interface DonutDataItem {
  label: string;
  value: number;
  color: string;
}

interface ShareCardDonutProps {
  data: DonutDataItem[];
  size: number;
  strokeWidth: number;
}

export function ShareCardDonut({ data, size, strokeWidth }: ShareCardDonutProps) {
  const total = data.reduce((s, d) => s + d.value, 0);
  if (total === 0) return null;

  const r = (size - strokeWidth) / 2;
  const cx = size / 2;
  const cy = size / 2;
  const circumference = 2 * Math.PI * r;

  // Build segments with cumulative offset
  let cumulativeOffset = 0;
  // SVG starts at 3 o'clock; rotate -90deg to start from 12 o'clock
  const segments = data.map((d) => {
    const dashLen = (d.value / total) * circumference;
    const dashGap = circumference - dashLen;
    const offset = circumference - cumulativeOffset;
    cumulativeOffset += dashLen;
    return { ...d, dashLen, dashGap, offset };
  });

  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: '14px' }}>
      {/* Donut */}
      <svg
        width={size}
        height={size}
        style={{ transform: 'rotate(-90deg)', flexShrink: 0 }}
      >
        {/* Track */}
        <circle
          cx={cx}
          cy={cy}
          r={r}
          fill="none"
          stroke="rgba(255,255,255,0.07)"
          strokeWidth={strokeWidth}
        />
        {/* Segments */}
        {segments.map((seg, i) => (
          <circle
            key={i}
            cx={cx}
            cy={cy}
            r={r}
            fill="none"
            stroke={seg.color}
            strokeWidth={strokeWidth}
            strokeDasharray={`${seg.dashLen} ${seg.dashGap}`}
            strokeDashoffset={seg.offset}
            strokeLinecap="butt"
          />
        ))}
      </svg>

      {/* Legend */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
        {data.map((d, i) => {
          const pct = Math.round((d.value / total) * 100);
          return (
            <div key={i} style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
              <div
                style={{
                  width: '8px',
                  height: '8px',
                  borderRadius: '50%',
                  backgroundColor: d.color,
                  flexShrink: 0,
                }}
              />
              <span style={{ fontSize: '11px', color: '#94a3b8', whiteSpace: 'nowrap' }}>
                {d.label}
              </span>
              <span style={{ fontSize: '11px', color: '#475569', marginLeft: '2px' }}>
                {pct}%
              </span>
            </div>
          );
        })}
      </div>
    </div>
  );
}
